const raw = JSON.stringify($json).slice(0, 2000);
console.log('[INGRESS superlikers-tg]', raw);
return $json;

const m = $json.message || {};
const photos = Array.isArray(m.photo) ? m.photo : [];
const best = photos.length ? photos[photos.length - 1] : null;
return {
  chatId: m.chat ? String(m.chat.id) : '',
  text: m.text || m.caption || '',
  hasMedia: !!best,
  fileId: best ? best.file_id : '',
  mediaType: best ? 'image' : ''
};

const sess = $json && $json.chatId ? $json : {};
const inp = $('Normalize Telegram Input').item.json;
const currentStep = Number(sess.currentStep || 1);
const stepMap = { 1: 'phone', 3: 'name', 4: 'email', 5: 'confirm', 6: 'photo', 9: 'done' };
let state = stepMap[currentStep] || 'phone';
if (state === 'done' && inp.hasMedia) state = 'photo';
return {
  chatId: inp.chatId,
  text: inp.text,
  typedPhone: String(inp.text || '').replace(/\D/g, ''),
  hasMedia: inp.hasMedia,
  fileId: inp.fileId,
  currentStep,
  state,
  phone: sess.phone || '',
  distinctId: sess.distinctId || '',
  name: sess.name || '',
  email: sess.email || '',
  photoActivityId: sess.photoActivityId || ''
};

const ctx = $('Resolve Context').item.json;
const res = $json || {};
const data = res.data || {};
const list = data.participants || data.results || (Array.isArray(data) ? data : []);
const found = list && list.length ? list[0] : null;
const typedPhone = ctx.typedPhone || '';
if (found && (found.email || found.distinct_id)) {
  return {
    chatId: ctx.chatId, phone: typedPhone,
    nextStep: 6,
    distinctId: found.email || found.distinct_id,
    name: found.name || ctx.name || '',
    email: found.email || '',
    photoActivityId: '', invoiceRef: '',
    replyText: '¡Te encontré! 📸 Mandame la foto de tu ticket o factura.',
    status: 'awaiting_photo'
  };
}
return {
  chatId: ctx.chatId, phone: typedPhone,
  nextStep: 3,
  distinctId: '', name: ctx.name || '', email: '', photoActivityId: '', invoiceRef: '',
  replyText: '¡Hola! Para registrarte, ¿cuál es tu nombre completo?',
  status: 'awaiting_name'
};

const ctx = $('Resolve Context').item.json;
return {
  chatId: ctx.chatId, phone: ctx.phone,
  nextStep: 1, distinctId: ctx.distinctId, name: ctx.name, email: ctx.email,
  photoActivityId: ctx.photoActivityId, invoiceRef: '',
  replyText: 'Pasame tu número de celular (solo números, 10 dígitos) 📱',
  status: 'awaiting_phone'
};

const ctx = $('Resolve Context').item.json;
const text = (ctx.text || '').trim();
if (text) {
  return {
    chatId: ctx.chatId, phone: ctx.phone,
    nextStep: 4, distinctId: ctx.distinctId, name: text, email: ctx.email,
    photoActivityId: ctx.photoActivityId, invoiceRef: '',
    replyText: '¡Gracias! Ahora tu correo electrónico ✉️',
    status: 'awaiting_email'
  };
}
return {
  chatId: ctx.chatId, phone: ctx.phone,
  nextStep: 3, distinctId: ctx.distinctId, name: ctx.name, email: ctx.email,
  photoActivityId: ctx.photoActivityId, invoiceRef: '',
  replyText: 'No te entendí. ¿Cuál es tu nombre completo?',
  status: 'awaiting_name'
};

const ctx = $('Resolve Context').item.json;
const email = (ctx.text || '').trim().toLowerCase();
return {
  chatId: ctx.chatId, phone: ctx.phone,
  nextStep: 5, distinctId: email, name: ctx.name, email: email,
  photoActivityId: ctx.photoActivityId, invoiceRef: '',
  replyText: 'Confirmemos: Nombre ' + ctx.name + ', Cel ' + ctx.phone + ', Correo ' + email + '. ¿Es correcto? Respondé SÍ para continuar.',
  status: 'awaiting_confirm'
};

const ctx = $('Resolve Context').item.json;
return {
  chatId: ctx.chatId, phone: ctx.phone,
  nextStep: 4, distinctId: ctx.distinctId, name: ctx.name, email: ctx.email,
  photoActivityId: ctx.photoActivityId, invoiceRef: '',
  replyText: 'Ese correo no parece válido. Mandámelo de nuevo ✉️',
  status: 'awaiting_email'
};

const ctx = $('Resolve Context').item.json;
return {
  chatId: ctx.chatId, phone: ctx.phone,
  nextStep: 6, distinctId: ctx.email, name: ctx.name, email: ctx.email,
  photoActivityId: '', invoiceRef: '',
  replyText: '¡Listo, quedaste registrado! 📸 Mandame la foto de tu ticket.',
  status: 'awaiting_photo'
};

const ctx = $('Resolve Context').item.json;
return {
  chatId: ctx.chatId, phone: ctx.phone,
  nextStep: 3, distinctId: '', name: '', email: '',
  photoActivityId: '', invoiceRef: '',
  replyText: 'Sin problema, empecemos de nuevo. ¿Tu nombre?',
  status: 'awaiting_name'
};

const ctx = $('Resolve Context').item.json;
const reply = $json.reply_text || 'No te entendí. Respondé SÍ para confirmar o NO para corregir.';
return {
  chatId: ctx.chatId, phone: ctx.phone,
  nextStep: 5, distinctId: ctx.distinctId, name: ctx.name, email: ctx.email,
  photoActivityId: ctx.photoActivityId, invoiceRef: '',
  replyText: reply,
  status: 'awaiting_confirm'
};

const ctx = $('Resolve Context').item.json;
return {
  chatId: ctx.chatId, phone: ctx.phone,
  nextStep: 6, distinctId: ctx.distinctId, name: ctx.name, email: ctx.email,
  photoActivityId: ctx.photoActivityId, invoiceRef: '',
  replyText: 'No pude descargar tu foto, reintentá 📷',
  status: 'awaiting_photo'
};

const ctx = $('Resolve Context').item.json;
return {
  chatId: ctx.chatId, phone: ctx.phone,
  nextStep: 6, distinctId: ctx.distinctId, name: ctx.name, email: ctx.email,
  photoActivityId: ctx.photoActivityId, invoiceRef: '',
  replyText: 'Necesito la *foto* de tu ticket 📸 (no texto).',
  status: 'awaiting_photo'
};

const ctx = $('Resolve Context').item.json;
return {
  chatId: ctx.chatId, phone: ctx.phone,
  nextStep: 1, distinctId: ctx.distinctId, name: ctx.name, email: ctx.email,
  photoActivityId: ctx.photoActivityId, invoiceRef: '',
  replyText: '¡Hola! Para empezar, pasame tu número de celular (10 dígitos) 📱',
  status: 'awaiting_phone'
};

const up = $('Upload Photo').item.json; const upBody = up.body || up;
const upStr = JSON.stringify(upBody || {}).toLowerCase();
const sha1Taken = upStr.includes('sha1 is already taken');
const activityId = (upBody && (upBody.id || (upBody.activity && upBody.activity.id) || upBody.entry)) || '';
const v = $('Read Invoice (Vision)').item.json;
const ctx = $('Resolve Context').item.json;
return { chatId: ctx.chatId, phone: ctx.phone, distinctId: ctx.distinctId, name: ctx.name, email: ctx.email, sha1Taken, activityId, legible: !!v.legible, ref: v.ref || '', products: v.products || [], detected_type: v.detected_type || 'desconocido' };

const d = $('Combine & Decide').item.json;
return {
  chatId: d.chatId, phone: d.phone,
  nextStep: 6, distinctId: d.distinctId, name: d.name, email: d.email,
  photoActivityId: d.activityId, invoiceRef: '',
  replyText: 'Ese ticket ya fue registrado antes ✋',
  status: 'awaiting_photo'
};

const d = $('Combine & Decide').item.json;
return {
  chatId: d.chatId, phone: d.phone,
  nextStep: 6, distinctId: d.distinctId, name: d.name, email: d.email,
  photoActivityId: d.activityId, invoiceRef: '',
  replyText: 'Esa compra ya generó puntos ✋',
  status: 'awaiting_photo'
};

const d = $('Combine & Decide').item.json;
const buy = $('Retail Buy').item.json || {};
const acc = $json || {};
const execErr = (acc.data && acc.data.execution_error) || (buy.data && buy.data.execution_error) || acc.errorType === 'execution_error' || buy.errorType === 'execution_error';
if (execErr) {
  return {
    chatId: d.chatId, phone: d.phone,
    nextStep: 9, distinctId: d.distinctId, name: d.name, email: d.email,
    photoActivityId: d.activityId, invoiceRef: d.ref,
    replyText: 'Tu ticket quedó en revisión manual 🕒',
    status: 'manual_review'
  };
}
const points = (buy.data && (buy.data.points || buy.data.earned_points)) || (acc.data && acc.data.points) || '';
return {
  chatId: d.chatId, phone: d.phone,
  nextStep: 9, distinctId: d.distinctId, name: d.name, email: d.email,
  photoActivityId: d.activityId, invoiceRef: d.ref,
  replyText: points ? ('🎉 ¡Listo! Ganaste ' + points + ' puntos.') : '🎉 ¡Listo! Ganaste tus puntos.',
  status: 'completed'
};

const d = $('Combine & Decide').item.json;
return {
  chatId: d.chatId, phone: d.phone,
  nextStep: 6, distinctId: d.distinctId, name: d.name, email: d.email,
  photoActivityId: d.activityId, invoiceRef: '',
  replyText: 'Hubo un problema registrando tu compra, intentá más tarde',
  status: 'awaiting_photo'
};

const d = $('Combine & Decide').item.json;
return {
  chatId: d.chatId, phone: d.phone,
  nextStep: 6, distinctId: d.distinctId, name: d.name, email: d.email,
  photoActivityId: '', invoiceRef: '',
  replyText: 'Recibí un/a ' + (d.detected_type || 'documento') + ', no un ticket 📷. Mandame una foto clara de tu factura (JPG/PNG).',
  status: 'awaiting_photo'
};

const rec = {
  ts: new Date().toISOString(),
  chatId: $json.chatId || '',
  phone: $json.phone || '',
  distinctId: $json.distinctId || '',
  invoiceRef: $json.invoiceRef || '',
  status: $json.status || '',
  nextStep: $json.nextStep
};
console.log('[TX superlikers-tg]', JSON.stringify(rec));
return $json;
